INSERT INTO `product` (`brand_id`, `category_id`, `colume_ml`, `product_id`, `unit_price`, `created_at`, `last_updated`, `description`, `created_by`, `last_updated_by`, `name`, `perfume_concentration`, `perfume_longevity`, `release_year`, `status`) VALUES
	(1, 1, 150, 1, 1710000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'YSL Black Opium EDP của Yves Saint Laurent là hương thơm tinh tế dành cho nữ, được ra mắt vào năm 2024.\r\n\r\nNhanh chóng đưa người dùng vào sự sảng khoái của Quả lê, Hạt tiêu hồng, Hoa cam, YSL Black Opium EDP nhanh chóng đưa người dùng vào một hành trình hương thơm phức tạp. Tầng hương giữa là sự cân bằng của Cà phê, Hoa nhài, Hạnh Nhân đắng, Cam thảo tỏa sáng, tạo nên một dấu ấn quyến rũ và khó phai. Để lại một vệt hương Vani, Hoắc hương, Gỗ Cashmere, Gỗ tuyết tùng lưu luyến, để lại một vệt hương lưu luyến và đầy bí ẩn.\r\n\r\nHương đầu: Quả lê, Hạt tiêu hồng, Hoa cam\r\nHương giữa: Cà phê, Hoa nhài, Hạnh Nhân đắng, Cam thảo\r\nHương cuối: Vani, Hoắc hương, Gỗ Cashmere, Gỗ tuyết tùng', 'admin1@gmail.com', 'admin1@gmail.com', 'YSL Black Opium EDP', '6-8 hours', '1-3%', '2024', 'ACTIVE'),
	(1, 2, 100, 2, 1010000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'YSL Y EDP của Yves Saint Laurent là hương thơm sang trọng dành cho nam, được ra mắt vào năm 2024.\r\n\r\nNhanh chóng đưa người dùng vào sự tươi mát của Táo xanh, Gừng, Cam Bergamot, YSL Y EDP tạo nên một khởi đầu một hành trình hương thơm phức tạp. Trung tâm của mùi hương là Cây xô thơm, Quả bách xù, Hoa phong lữ tỏa sáng, tạo nên một dấu ấn tinh tế và khó phai. Tầng hương cuối khép lại với Hổ phách, Đậu Tonka, Gỗ tuyết tùng , Cỏ Vetiver, Olibanum ấm áp, để lại một vệt hương khó phai và khẳng định đẳng cấp.\r\n\r\nHương đầu: Táo xanh, Gừng, Cam Bergamot\r\nHương giữa: Cây xô thơm, Quả bách xù, Hoa phong lữ\r\nHương cuối: Hổ phách, Đậu Tonka, Gỗ tuyết tùng , Cỏ Vetiver, Olibanum', 'admin1@gmail.com', 'admin1@gmail.com', 'YSL Y EDP', '6-8 hours', '15-40%', '2024', 'ACTIVE'),
	(2, 3, 100, 3, 1120000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Santal 33 của Le Labo là hương thơm sang trọng dành cho unisex, được ra mắt vào năm 2024.\r\n\r\nMở ra một hành trình sự tươi mới của Bưởi, Quýt, Santal 33 nhanh chóng đưa người dùng vào một hành trình hương thơm phức tạp. Trái tim của hương thơm là Hoa huệ, Hoa nhài tỏa sáng, tạo nên một dấu ấn sang trọng và khó phai. Lưu lại trên da là Gỗ đàn hương, Vani đẳng cấp, để lại một vệt hương gợi cảm và đầy bí ẩn.\r\n\r\nHương đầu: Bưởi, Quýt\r\nHương giữa: Hoa huệ, Hoa nhài\r\nHương cuối: Gỗ đàn hương, Vani', 'admin1@gmail.com', 'admin1@gmail.com', 'Santal 33', '4-5 hours', '15-20%', '2024', 'ACTIVE'),
	(3, 1, 150, 4, 1390000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Bright Crystal của Versace là hương thơm lãng mạn dành cho nữ, được ra mắt vào năm 2024.\r\n\r\nMở ra một hành trình sự tinh khôi của Hương An-đê-hít, Quýt, Bright Crystal mở ra một hành trình một hành trình hương thơm phức tạp. Tiếp nối là tầng hương của Hoa ngọc lan tây, Hoa cam tỏa sáng, tạo nên một dấu ấn lãng mạn và khó phai. Lưu lại trên da là Cỏ Vetiver, Vani khó phai, để lại một vệt hương đẳng cấp và khẳng định đẳng cấp.\r\n\r\nHương đầu: Hương An-đê-hít, Quýt\r\nHương giữa: Hoa ngọc lan tây, Hoa cam\r\nHương cuối: Cỏ Vetiver, Vani', 'admin1@gmail.com', 'admin1@gmail.com', 'Bright Crystal', '2-3 hours', '5-15%', '2024', 'ACTIVE'),
	(4, 3, 120, 5, 1350000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'L’eau Papier EDT của Diptyque là hương thơm lãng mạn dành cho unisex, được ra mắt vào năm 2024.\r\n\r\nNhanh chóng đưa người dùng vào sự lôi cuốn của Bạc hà, Táo xanh, L’eau Papier EDT dẫn dắt khứu giác tới một hành trình hương thơm phức tạp. Trái tim của hương thơm là Cây diên vĩ, Hoa nhài tỏa sáng, tạo nên một dấu ấn thanh lịch và khó phai. Cuối cùng, lắng đọng lại là Hổ phách, Cỏ Vetiver sâu lắng, để lại một vệt hương gợi cảm và đầy bí ẩn.\r\n\r\nHương đầu: Bạc hà, Táo xanh\r\nHương giữa: Cây diên vĩ, Hoa nhài\r\nHương cuối: Hổ phách, Cỏ Vetiver', 'admin1@gmail.com', 'admin1@gmail.com', 'L’eau Papier EDT', '1-2 hours', '1-3%', '2024', 'ACTIVE'),
	(5, 3, 130, 6, 1340000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Khaltar Night của Attar Collection là hương thơm thanh lịch dành cho unisex, được ra mắt vào năm 2024.\r\n\r\nMở ra một hành trình sự tươi mới của Tiêu hồng, Bạc hà, Khaltar Night tạo nên một khởi đầu một hành trình hương thơm phức tạp. Tầng hương giữa là sự cân bằng của Hoa nhài, Cây diên vĩ tỏa sáng, tạo nên một dấu ấn quyến rũ và khó phai. Tầng hương cuối khép lại với Xạ hương, Rêu sồi khó phai, để lại một vệt hương đẳng cấp và khẳng định đẳng cấp.\r\n\r\nHương đầu: Tiêu hồng, Bạc hà\r\nHương giữa: Hoa nhài, Cây diên vĩ\r\nHương cuối: Xạ hương, Rêu sồi', 'admin1@gmail.com', 'admin1@gmail.com', 'Khaltar Night', '4-5 hours', '15-40%', '2024', 'ACTIVE'),
	(6, 3, 150, 7, 1620000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Lost Cherry của Tom Ford là hương thơm tinh tế dành cho unisex, được ra mắt vào năm 2024.\r\n\r\nDẫn dắt khứu giác tới sự tươi mới của Hạnh nhân, Hương rượu, Cherry đen, Lost Cherry tạo nên một khởi đầu một hành trình hương thơm phức tạp. Trung tâm của mùi hương là Cherry đỏ, Quả mận, Hoa hồng Thổ Nhĩ Kỳ, Hoa nhài Sambac tỏa sáng, tạo nên một dấu ấn mạnh mẽ và khó phai. Tầng hương cuối khép lại với Đậu Tonka, Vanilla, Quế, Nhựa hương Peru, Nhựa hương Benzoin, Gỗ đàn hương, Đinh hương, Gỗ tuyết tùng, Hoắc hương, Cỏ hương bài bí ẩn, để lại một vệt hương khó phai và đầy bí ẩn.\r\n\r\nHương đầu: Hạnh nhân, Hương rượu, Cherry đen\r\nHương giữa: Cherry đỏ, Quả mận, Hoa hồng Thổ Nhĩ Kỳ, Hoa nhài Sambac\r\nHương cuối: Đậu Tonka, Vanilla, Quế, Nhựa hương Peru, Nhựa hương Benzoin, Gỗ đàn hương, Đinh hương, Gỗ tuyết tùng, Hoắc hương, Cỏ hương bài', 'admin1@gmail.com', 'admin1@gmail.com', 'Lost Cherry', '4-5 hours', '1-3%', '2024', 'ACTIVE'),
	(3, 2, 90, 8, 930000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Eros EDT của Versace là hương thơm sang trọng dành cho nam, được ra mắt vào năm 2024.\r\n\r\nTạo nên một khởi đầu sự tươi mới của Bạc hà, Táo xanh, Quả chanh vàng, Eros EDT tạo nên một khởi đầu một hành trình hương thơm phức tạp. Tiếp nối là tầng hương của Đậu Tonka, Ambroxan, Geranium tỏa sáng, tạo nên một dấu ấn nữ tính và khó phai. Để lại một vệt hương Vanilla, Gỗ tuyết tùng, Cỏ hương bài, Rêu sồi cuốn hút, để lại một vệt hương bí ẩn và khẳng định đẳng cấp.\r\n\r\nHương đầu: Bạc hà, Táo xanh, Quả chanh vàng\r\nHương giữa: Đậu Tonka, Ambroxan, Geranium\r\nHương cuối: Vanilla, Gỗ tuyết tùng, Cỏ hương bài, Rêu sồi', 'admin1@gmail.com', 'admin1@gmail.com', 'Eros EDT', '6-8 hours', '15-40%', '2024', 'ACTIVE'),
	(7, 1, 130, 9, 1450000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Gucci Bloom EDP của Gucci là hương thơm mạnh mẽ dành cho nữ, được ra mắt vào năm 2024.\r\n\r\nDẫn dắt khứu giác tới sự sống động của Cam Bergamot, Tiêu hồng, Gucci Bloom EDP nhanh chóng đưa người dùng vào một hành trình hương thơm phức tạp. Trái tim của hương thơm là Hoa ngọc lan tây, Hoa hồng tỏa sáng, tạo nên một dấu ấn đặc trưng và khó phai. Tầng hương cuối khép lại với Hoắc hương, Hổ phách lưu luyến, để lại một vệt hương ấm áp và khẳng định đẳng cấp.\r\n\r\nHương đầu: Cam Bergamot, Tiêu hồng\r\nHương giữa: Hoa ngọc lan tây, Hoa hồng\r\nHương cuối: Hoắc hương, Hổ phách', 'admin1@gmail.com', 'admin1@gmail.com', 'Gucci Bloom EDP', '4-5 hours', '5-15%', '2024', 'ACTIVE'),
	(8, 3, 100, 10, 1120000, '2025-10-19 00:00:00.000000', '2025-10-19 00:00:00.000000', 'Exnihilo Fleur Narcotique EDP của Ex Nihilo là hương thơm thanh lịch dành cho unisex, được ra mắt vào năm 2024.\r\n\r\nDẫn dắt khứu giác tới sự sống động của Cam Bergamot, Chanh vàng, Exnihilo Fleur Narcotique EDP dẫn dắt khứu giác tới một hành trình hương thơm phức tạp. Trung tâm của mùi hương là Hoa nhài, Hoa ngọc lan tây tỏa sáng, tạo nên một dấu ấn sang trọng và khó phai. Để lại một vệt hương Xạ hương, Vani ấm áp, để lại một vệt hương lưu luyến và đầy bí ẩn.\r\n\r\nHương đầu: Cam Bergamot, Chanh vàng\r\nHương giữa: Hoa nhài, Hoa ngọc lan tây\r\nHương cuối: Xạ hương, Vani', 'admin1@gmail.com', 'admin1@gmail.com', 'Exnihilo Fleur Narcotique EDP', '2-3 hours', '15-40%', '2024', 'ACTIVE'),
